  2257в†’
  2258в†’Generate and maintain the 1-10 year strategic plan using genetic algorithms, constrained by capacity envelopes from the tactical model.
  2259в†’
  2260в†’### 4.5.2 Implementation
  2261в†’
  2262в†’```typescript
  2263в†’interface StrategicPlannerConfig {
  2264в†’  horizonYears: number;          // 10
  2265в†’  granularity: 'MONTHLY' | 'QUARTERLY';
  2266в†’  populationSize: number;        // 100
  2267в†’  generations: number;           // 500
  2268в†’  mutationRate: number;          // 0.1
  2269в†’  eliteCount: number;            // 10
  2270в†’}
  2271в†’
  2272в†’interface StrategicAllocation {
  2273в†’  trainId: string;
  2274в†’  pmTypeId: string;
  2275в†’  targetQuarter: string;  // e.g., '2028-Q2'
  2276в†’  estimatedHours: number;
  2277в†’  estimatedCost: number;
  2278в†’}
  2279в†’
  2280в†’class StrategicPlanner {
  2281в†’  private constraintAggregation: ConstraintAggregationService;
  2282в†’  
  2283в†’  async generatePlan(
  2284в†’    fromBaseline: string | null
  2285в†’  ): Promise<StrategicPlanResult> {
  2286в†’    // 1. Load current fleet state
  2287в†’    const fleetState = await this.getFleetState();
  2288в†’    
  2289в†’    // 2. Project PM requirements for each train
  2290в†’    const pmRequirements = await this.projectPMRequirements(
  2291в†’      fleetState,
  2292в†’      this.config.horizonYears
  2293в†’    );
  2294в†’    
  2295в†’    // 3. Generate constraint envelopes for each quarter
  2296в†’    const envelopes = await this.generateEnvelopes();
  2297в†’    
  2298в†’    // 4. Run genetic algorithm
  2299в†’    const bestPlan = await this.runGeneticAlgorithm(
  2300в†’      pmRequirements,
  2301в†’      envelopes
  2302в†’    );
  2303в†’    
  2304в†’    // 5. Validate against constraint envelopes
  2305в†’    const validation = await this.validatePlan(bestPlan, envelopes);
  2306в†’    
  2307в†’    if (!validation.valid) {
  2308в†’      // Attempt repair
  2309в†’      const repairedPlan = await this.repairPlan(bestPlan, validation);
  2310в†’      return {
  2311в†’        plan: repairedPlan,
  2312в†’        validation: await this.validatePlan(repairedPlan, envelopes),
  2313в†’        metrics: this.calculateMetrics(repairedPlan)
  2314в†’      };
  2315в†’    }
  2316в†’    
  2317в†’    return {
  2318в†’      plan: bestPlan,
  2319в†’      validation,
  2320в†’      metrics: this.calculateMetrics(bestPlan)
  2321в†’    };
  2322в†’  }
  2323в†’  
  2324в†’  /**
  2325в†’   * Project PM requirements for all trains over the planning horizon.
  2326в†’   * 
  2327в†’   * CRITICAL: This implementation correctly handles:
  2328в†’   * 1. PM hierarchy (C4 satisfies C1/C2/C3 - resets their counters)
  2329в†’   * 2. Dual triggers (mileage OR time, whichever comes first)
  2330в†’   * 3. Recent velocity calculation for accurate projections
  2331в†’   * 4. Cascading projections (each PM feeds into next cycle)
  2332в†’   */
  2333в†’  private async projectPMRequirements(
  2334в†’    fleetState: FleetState,
  2335в†’    horizonYears: number
  2336в†’  ): Promise<PMRequirement[]> {
  2337в†’    const requirements: PMRequirement[] = [];
  2338в†’    const horizonEnd = addYears(new Date(), horizonYears);
  2339в†’    
  2340в†’    for (const train of fleetState.trains) {
  2341в†’      const trainRules = await this.getPMRulesForFleet(train.fleetId);
  2342в†’      const trainHistory = await this.getPMHistoryForTrain(train.id);
  2343в†’      
  2344в†’      // Calculate daily utilization for this train
  2345в†’      const dailyKm = this.calculateDailyUtilization(train, trainHistory);
  2346в†’      
  2347в†’      // Project all PM types for this train
  2348в†’      const trainProjections = await this.projectTrainPMs(
  2349в†’        train,
  2350в†’        trainRules,
  2351в†’        trainHistory,
  2352в†’        horizonEnd,
  2353в†’        dailyKm
  2354в†’      );
  2355в†’      
  2356в†’      requirements.push(...trainProjections);
  2357в†’    }
  2358в†’    
  2359в†’    return requirements;
  2360в†’  }
  2361в†’  
  2362в†’  /**
  2363в†’   * Project all PM events for a single train over the horizon.
  2364в†’   */
  2365в†’  private async projectTrainPMs(
  2366в†’    train: Train,
  2367в†’    pmRules: PMType[],
  2368в†’    pmHistory: PMHistory[],
  2369в†’    horizonEnd: Date,
  2370в†’    dailyKm: number
  2371в†’  ): Promise<PMRequirement[]> {
  2372в†’    const projections: PMRequirement[] = [];
  2373в†’    
  2374в†’    // Create working state (mutable copy of history + projections)
  2375в†’    let workingHistory = [...pmHistory];
  2376в†’    let currentMileage = train.currentMileageKm;
  2377в†’    let currentDate = new Date();
  2378в†’    
  2379в†’    // Project until we exceed horizon
  2380в†’    while (currentDate < horizonEnd) {
  2381в†’      // Find next PM due across all PM types
  2382в†’      let nextPM: { 
  2383в†’        rule: PMType; 
  2384в†’        date: Date; 
  2385в†’        mileage: number; 
  2386в†’        trigger: 'MILEAGE' | 'TIME' 
  2387в†’      } | null = null;
  2388в†’      
  2389в†’      for (const rule of pmRules) {
  2390в†’        const projection = this.calculateNextPMDue(
  2391в†’          train,
  2392в†’          rule,
  2393в†’          pmRules,
  2394в†’          workingHistory,
  2395в†’          currentMileage,
  2396в†’          currentDate,
  2397в†’          dailyKm
  2398в†’        );
  2399в†’        
  2400в†’        if (!nextPM || projection.date < nextPM.date) {
  2401в†’          nextPM = {
  2402в†’            rule,
  2403в†’            date: projection.date,
  2404в†’            mileage: projection.mileage,
  2405в†’            trigger: projection.trigger
  2406в†’          };
  2407в†’        }
  2408в†’      }
  2409в†’      
  2410в†’      if (!nextPM || nextPM.date > horizonEnd) break;
  2411в†’      
  2412в†’      // Create requirement
  2413в†’      const requirement: PMRequirement = {
  2414в†’        id: generateUUID(),
  2415в†’        trainId: train.id,
  2416в†’        trainNumber: train.trainNumber,
  2417в†’        pmTypeId: nextPM.rule.id,
  2418в†’        pmCode: nextPM.rule.pmCode,
  2419в†’        projectedDate: nextPM.date,
  2420в†’        projectedMileageKm: nextPM.mileage,
  2421в†’        triggerType: nextPM.trigger,
  2422в†’        confidence: workingHistory.length > 0 ? 'HISTORICAL' : 'ESTIMATED',
  2423в†’        estimatedHours: nextPM.rule.estimatedHours,
  2424в†’        trackType: nextPM.rule.trackType,
  2425в†’        durationDays: nextPM.rule.minTrackDays,
  2426в†’        // Compliance window (ГѓвЂљГ‚В±10% of interval by default)
  2427в†’        constraintStart: addDays(nextPM.date, -Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm)),
  2428в†’        constraintEnd: addDays(nextPM.date, Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm))
  2429в†’      };
  2430в†’      
  2431в†’      projections.push(requirement);
  2432в†’      
  2433в†’      // Add to working history for cascading projection
  2434в†’      workingHistory.push({
  2435в†’        id: requirement.id,
  2436в†’        trainId: train.id,
  2437в†’        pmTypeId: nextPM.rule.id,
  2438в†’        pmCode: nextPM.rule.pmCode,
  2439в†’        completionDate: nextPM.date,
  2440в†’        mileageAtCompletion: nextPM.mileage
  2441в†’      });
  2442в†’      
  2443в†’      // Advance state past this PM
  2444в†’      currentDate = addDays(nextPM.date, nextPM.rule.minTrackDays);
  2445в†’      currentMileage = nextPM.mileage + (nextPM.rule.minTrackDays * dailyKm * 0.1);
  2446в†’    }
  2447в†’    
  2448в†’    return projections;
  2449в†’  }
  2450в†’  
  2451в†’  /**
  2452в†’   * Calculate when the next instance of a specific PM type is due.
  2453в†’   * 
  2454в†’   * CRITICAL: Accounts for PM hierarchy - a C4 satisfies C1/C2/C3 requirements,
  2455в†’   * so the mileage counter resets from the C4 completion point.
  2456в†’   * 
  2457в†’   * CRITICAL: Handles "Cold Start" case where train has no PM history.
  2458в†’   * Without this fix, trains with high mileage and no history would show
  2459в†’   * ALL PMs as overdue immediately.
  2460в†’   */
  2461в†’  private calculateNextPMDue(
  2462в†’    train: Train,
  2463в†’    targetRule: PMType,
  2464в†’    allRules: PMType[],
  2465в†’    history: PMHistory[],
  2466в†’    currentMileage: number,
  2467в†’    currentDate: Date,
  2468в†’    dailyKm: number
  2469в†’  ): { date: Date; mileage: number; trigger: 'MILEAGE' | 'TIME' } {
  2470в†’    
  2471в†’    // 1. Find all PM types that SATISFY the target PM
  2472в†’    // (the target itself + any higher-level PM that includes target in satisfiesCodes)
  2473в†’    const satisfyingCodes = this.getSatisfyingCodes(targetRule.pmCode, allRules);
  2474в†’    
  2475в†’    // 2. Find the most recent PM that satisfies this requirement
  2476в†’    const lastSatisfying = history
  2477в†’      .filter(h => satisfyingCodes.includes(h.pmCode))
  2478в†’      .sort((a, b) => b.mileageAtCompletion - a.mileageAtCompletion)[0];
  2479в†’    
  2480в†’    // 3. Handle "Cold Start" - no PM history exists
  2481в†’    //    Assume train has been maintained on schedule since commissioning.
  2482в†’    //    Calculate which cycle we're currently in and when it started.
  2483в†’    let lastMileage: number;
  2484в†’    let lastDate: Date;
  2485в†’    
  2486в†’    if (lastSatisfying) {
  2487в†’      // Normal case: use actual history
  2488в†’      lastMileage = lastSatisfying.mileageAtCompletion;
  2489в†’      lastDate = new Date(lastSatisfying.completionDate);
  2490в†’    } else {
  2491в†’      // COLD START FIX: Create "virtual" last PM
  2492в†’      // Calculate how many complete cycles since commissioning
  2493в†’      const cyclesCompleted = Math.floor(currentMileage / targetRule.intervalKm);
  2494в†’      
  2495в†’      if (cyclesCompleted > 0) {
  2496в†’        // Assume last PM occurred at start of current cycle
  2497в†’        lastMileage = cyclesCompleted * targetRule.intervalKm;
